import Box from '@mui/material/Box'
import Image from 'next/image'

interface BrandLogoProps {
  size?: number
  variant?: 'dark' | 'light'
  showText?: boolean
}

export default function BrandLogo({ size = 36, variant = 'dark', showText = true }: BrandLogoProps) {
  const textColor = variant === 'dark' ? '#1F1F1F' : '#FFFFFF'
  const taglineColor = variant === 'dark' ? 'var(--text-subtitle)' : 'var(--text-on-dark-muted)'

  return (
    <Box sx={{ display: 'inline-flex', alignItems: 'center', gap: '10px' }}>
      <Box
        sx={{
          width: size,
          height: size,
          borderRadius: '8px',
          backgroundColor: '#1F1F1F',
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
        }}
      >
        <Image
          src='/images/Logo.png'
          alt='Growve'
          width={size - 10}
          height={size - 10}
          style={{ objectFit: 'contain' }}
          priority
        />
      </Box>

      {showText && (
        <Box sx={{ display: 'flex', flexDirection: 'column', lineHeight: 1 }}>
          <Box
            component='span'
            sx={{
              color: textColor,
              fontWeight: 800,
              fontSize: '1.0625rem',
              letterSpacing: '0.05em',
              fontFamily: "'Nunito Sans', sans-serif",
            }}
          >
            GROWVE
          </Box>
          <Box
            component='span'
            sx={{
              color: taglineColor,
              fontWeight: 600,
              fontSize: '0.5625rem',
              letterSpacing: '0.24em',
              marginTop: '3px',
              fontFamily: "'Nunito Sans', sans-serif",
            }}
          >
            LOGISTICS
          </Box>
        </Box>
      )}
    </Box>
  )
}
